The `HoloScriptBridge` connects your code to the Hololand runtime for executing AST and syncing world state:

```hsplus
import { 
  createHoloScriptBridge, 
  BridgeState,
  ASTNode 
} from "@hololand/core"

// Create and connect
const bridge = createHoloScriptBridge({
  worldId: "my-world",
  enableDevTools: true
})

await bridge.connect()
console.log(bridge.getState()) // BridgeState.connected

// Execute AST nodes
const result = await bridge.execute({
  type: "object",
  id: "player-orb",
  properties: {
    position: [0, 1.5, 0],
    color: "#00ff00",
    traits: ["grabbable"]
  }
})

if (result.success) {
  console.log("Created:", result.entityId)
}

// Batch operations for efficiency
const results = await bridge.executeBatch([
  { type: "orb", id: "orb-1", properties: { position: [0, 0, 0] } },
  { type: "orb", id: "orb-2", properties: { position: [2, 0, 0] } },
  { type: "orb", id: "orb-3", properties: { position: [4, 0, 0] } }
])

// Query entities
const entity = bridge.getEntity("player-orb")
const orbs = bridge.queryEntities({ type: "orb" })
const nearby = bridge.queryEntities({ 
  position: { x: 0, y: 0, z: 0 }, 
  radius: 10 
})

// Event handling
bridge.on("entity:created", (entity) => {
  console.log("New entity:", entity.id)
})

bridge.on("entity:updated", (entity) => {
  console.log("Updated:", entity.id)
})

// DevTools integration
const devData = bridge.getDevToolsData()
const history = bridge.getExecutionHistory()

// Clean up
bridge.disconnect()
```

Bridge states:
- `BridgeState.disconnected` - Not connected
- `BridgeState.connecting` - Connection in progress
- `BridgeState.connected` - Ready to execute
- `BridgeState.error` - Connection failed

Use the test utilities from `@hololand/core` for comprehensive testing:

```hsplus
import {
  loadFixture,
  loadExample,
  createTestParser,
  parseExpectSuccess,
  parseExpectFailure,
  assertHasTrait,
  assertProperty,
  assertNodeType,
  generateOrb,
  generateScene,
  testAllTraitsParse,
  ALL_VR_TRAITS,
  MockEventEmitter,
  createMockNPC,
  createMockProjectile
} from "@hololand/core"

// Load test fixtures
const fixture = loadFixture("basic-orb")
const example = loadExample("researcher-viralist")

// Parse and validate
const ast = parseExpectSuccess(`
  orb "test" {
    position: [0, 1, 0]
    color: "#ff0000"
    traits: ["grabbable"]
    grabbable: { snap_to_hand: true }
  }
`)

// AST assertions
assertNodeType(ast, "orb")
assertProperty(ast, "color", "#ff0000")
assertHasTrait(ast, "grabbable", { snap_to_hand: true })

// Expect parse failures
const errors = parseExpectFailure("invalid { { { syntax")
console.log(errors) // Array of parse errors

// Generate test content
const orbSource = generateOrb("test-orb", ["grabbable", "glowing"], {
  color: "#0000ff",
  size: 0.5
})

const sceneSource = generateScene([
  { type: "orb", id: "a", traits: ["grabbable"] },
  { type: "cube", id: "b", traits: ["climbable"] }
])

// Test all 49 VR traits
const parser = createTestParser()
const results = testAllTraitsParse(parser)
console.log(`${results.passed}/${ALL_VR_TRAITS.length} traits passed`)

// Mock objects for testing
const npc = createMockNPC("guard", {
  position: [10, 0, 5],
  dialogue: ["Halt!", "Who goes there?"]
})
const response = npc.interact("greet")

const projectile = createMockProjectile("arrow", {
  position: [0, 1, 0],
  velocity: [10, 5, 0],
  damage: 25
})
projectile.update(0.1) // Simulate physics

// Event emitter for testing
const emitter = new MockEventEmitter()
emitter.on("hit", (data) => console.log("Hit!", data))
emitter.emit("hit", { target: "enemy" })
```

All 49 VR traits are available in `ALL_VR_TRAITS` including: grabbable, throwable, climbable, portal, physics, breakable, and more!
